/* Skip Link - Accessibility */
.skip-link {
  position: absolute;
  top: -100%;
  left: var(--s-4);
  z-index: 1000;
  padding: var(--s-2) var(--s-4);
  background: var(--c-aurora-cyan);
  color: var(--c-space-900);
  font-weight: 600;
  text-decoration: none;
  border-radius: var(--r-sm);
  transition: top var(--t-fast);
}
.skip-link:focus-visible {
  top: var(--s-2);
  outline: 2px solid var(--c-lum-100);
  outline-offset: 2px;
}

/* Game Shell - The Living Instrument */
#gameShell {
  position: relative;
  width: 100%;
  min-height: 100vh;
  min-height: 100dvh;
  display: flex;
  flex-direction: column;
  background:
    radial-gradient(ellipse at 20% 20%, rgba(0, 242, 254, 0.08) 0%, transparent 50%),
    radial-gradient(ellipse at 80% 10%, rgba(79, 0, 245, 0.08) 0%, transparent 50%),
    radial-gradient(ellipse at 40% 80%, rgba(0, 255, 133, 0.06) 0%, transparent 50%),
    radial-gradient(ellipse at 90% 90%, rgba(255, 0, 230, 0.06) 0%, transparent 50%),
    var(--c-space-900);
  overflow: hidden;
}

/* Canvas - The Sky Loom */
#gameCanvas {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  z-index: 1;
  display: block;
  pointer-events: none;
  background:
    linear-gradient(135deg, var(--c-space-800) 0%, var(--c-space-900) 50%, var(--c-space-800) 100%),
    repeating-linear-gradient(
      45deg,
      transparent,
      transparent 2px,
      rgba(0, 242, 254, 0.01) 2px,
      rgba(0, 242, 254, 0.01) 4px
    ),
    repeating-linear-gradient(
      -45deg,
      transparent,
      transparent 2px,
      rgba(79, 0, 245, 0.01) 2px,
      rgba(79, 0, 245, 0.01) 4px
    );
}

/* Phase Atmospheres - Applied to #gameShell via JS */
[data-phase="1"],
#gameShell:not([data-phase]) {
  --phase-primary: var(--c-aurora-cyan);
  --phase-secondary: var(--c-aurora-blue);
  --phase-glow: var(--shadow-glow-cyan);
  --phase-bg-accent: rgba(0, 242, 254, 0.12);
}

[data-phase="2"] {
  --phase-primary: var(--c-aurora-purple);
  --phase-secondary: var(--c-aurora-magenta);
  --phase-glow: var(--shadow-glow-purple);
  --phase-bg-accent: rgba(79, 0, 245, 0.12);
}

[data-phase="3"] {
  --phase-primary: var(--c-aurora-green);
  --phase-secondary: var(--c-aurora-gold);
  --phase-glow: var(--shadow-glow-green);
  --phase-bg-accent: rgba(0, 255, 133, 0.12);
}

[data-phase="4"] {
  --phase-primary: var(--c-lum-100);
  --phase-secondary: var(--c-aurora-cyan);
  --phase-glow: var(--shadow-glow-white);
  --phase-bg-accent: rgba(255, 255, 255, 0.15);
}

#gameShell[data-phase="1"] #gameCanvas {
  background:
    linear-gradient(135deg, var(--c-space-800) 0%, var(--c-space-900) 50%, var(--c-space-800) 100%),
    repeating-linear-gradient(45deg, transparent, transparent 2px, rgba(0, 242, 254, 0.02) 2px, rgba(0, 242, 254, 0.02) 4px);
}

#gameShell[data-phase="2"] #gameCanvas {
  background:
    linear-gradient(135deg, var(--c-space-800) 0%, var(--c-space-900) 50%, var(--c-space-800) 100%),
    repeating-linear-gradient(45deg, transparent, transparent 2px, rgba(79, 0, 245, 0.02) 2px, rgba(79, 0, 245, 0.02) 4px),
    repeating-linear-gradient(-45deg, transparent, transparent 2px, rgba(255, 0, 230, 0.015) 2px, rgba(255, 0, 230, 0.015) 4px);
}

#gameShell[data-phase="3"] #gameCanvas {
  background:
    linear-gradient(135deg, var(--c-space-800) 0%, var(--c-space-900) 50%, var(--c-space-800) 100%),
    repeating-linear-gradient(45deg, transparent, transparent 2px, rgba(0, 255, 133, 0.02) 2px, rgba(0, 255, 133, 0.02) 4px),
    repeating-linear-gradient(-45deg, transparent, transparent 2px, rgba(255, 215, 0, 0.015) 2px, rgba(255, 215, 0, 0.015) 4px);
}

#gameShell[data-phase="4"] #gameCanvas {
  background:
    radial-gradient(circle at center, rgba(255, 255, 255, 0.05) 0%, transparent 70%),
    linear-gradient(135deg, var(--c-space-800) 0%, var(--c-space-900) 50%, var(--c-space-800) 100%);
}

/* ------------------------------------------------------------------------
   UI ROOT & CONTAINER
   ------------------------------------------------------------------------ */
#uiRoot {
  position: relative;
  z-index: 10;
  width: 100%;
  max-width: 1600px;
  margin: 0 auto;
  padding: var(--s-4);
  padding-bottom: calc(var(--s-4) + env(safe-area-inset-bottom, 0px));
  min-height: 100vh;
  min-height: 100dvh;
  display: flex;
  flex-direction: column;
}

#uiRoot:focus-visible {
  outline: none;
}

.ui-container {
  display: flex;
  flex-direction: column;
  gap: var(--s-4);
  width: 100%;
  height: 100%;
  flex: 1;
  pointer-events: auto;
}

/* ------------------------------------------------------------------------
   TOP BAR - Stats Panel
   ------------------------------------------------------------------------ */
.top-bar {
  width: 100%;
  background: rgba(10, 10, 26, 0.7);
  backdrop-filter: blur(4px);
  -webkit-backdrop-filter: blur(4px);
  border: 1px solid rgba(0, 242, 254, 0.2);
  border-radius: var(--r-md);
  padding: var(--s-3);
  box-shadow: var(--shadow-inset);
}

.stats-panel {
  display: flex;
  flex-wrap: wrap;
  gap: var(--s-4);
  align-items: center;
}

.stat-row {
  display: flex;
  align-items: baseline;
  gap: var(--s-1);
  font-size: 0.875rem;
}

.stat-label {
  color: var(--c-lum-60);
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  font-size: 0.75rem;
}

.stat-value {
  color: var(--phase-primary);
  font-weight: 600;
  font-size: 1rem;
}

.stat-max {
  color: var(--c-lum-60);
  font-size: 0.875rem;
}

.stat-bar-container {
  flex: 1;
  min-width: 120px;
  max-width: 300px;
}

.stat-bar {
  width: 100%;
  height: 8px;
  background: rgba(0, 0, 0, 0.3);
  border-radius: var(--r-full);
  overflow: hidden;
  border: 1px solid rgba(255, 255, 255, 0.1);
}

.stat-bar-fill {
  height: 100%;
  width: 0%;
  background: linear-gradient(90deg, var(--phase-secondary), var(--phase-primary));
  border-radius: var(--r-full);
  transition: width var(--t-slow);
  box-shadow: var(--phase-glow);
}

/* Reservoir bar - special styling */
#reservoirBarFill {
  background: linear-gradient(
    90deg,
    var(--c-aurora-cyan) 0%,
    var(--c-aurora-purple) 50%,
    var(--c-aurora-magenta) 100%
  );
}

/* Pressure warning on bar */
[data-pressure="high"] .stat-bar-fill,
[data-pressure="critical"] .stat-bar-fill {
  background: linear-gradient(90deg, var(--c-warning), var(--c-danger));
  box-shadow: 0 0 12px rgba(255, 215, 0, 0.5);
}

/* ------------------------------------------------------------------------
   MAIN PANELS - Three-Column Desktop Layout
   ------------------------------------------------------------------------ */
.main-panels {
  display: grid;
  grid-template-columns: minmax(240px, 280px) 1fr minmax(240px, 280px);
  gap: var(--s-4);
  flex: 1;
  min-height: 0;
}

.panel-column {
  display: flex;
  flex-direction: column;
  gap: var(--s-3);
}

.left-column {
  grid-column: 1;
  width: 100%;
}

.right-column {
  grid-column: 3;
  width: 100%;
}

/* ------------------------------------------------------------------------
   PANELS - Shared Styles
   ------------------------------------------------------------------------ */
.panel {
  background: rgba(16, 20, 36, 0.75);
  backdrop-filter: blur(4px);
  -webkit-backdrop-filter: blur(4px);
  border: 1px solid rgba(0, 242, 254, 0.2);
  border-radius: var(--r-md);
  padding: var(--s-3);
  box-shadow: var(--shadow-inset);
  transition: border-color var(--t-normal), box-shadow var(--t-normal);
  overflow-y: auto;
  max-height: 100%;
}

.panel:focus-within {
  border-color: var(--phase-primary);
  box-shadow: 0 0 0 1px var(--phase-primary);
}

.panel-header {
  color: var(--phase-primary);
  font-size: 0.875rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: var(--s-2);
  padding-bottom: var(--s-2);
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.panel-desc {
  color: var(--c-lum-60);
  font-size: 0.8125rem;
  margin-bottom: var(--s-3);
  line-height: 1.5;
}

/* ------------------------------------------------------------------------
   PURCHASE PANEL - Weftlings
   ------------------------------------------------------------------------ */
.purchase-panel {
  min-height: 180px;
}

.purchase-list {
  display: flex;
  flex-direction: column;
  gap: var(--s-2);
}

.purchase-item {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: var(--s-2);
  padding: var(--s-2);
  background: rgba(0, 0, 0, 0.2);
  border-radius: var(--r-sm);
  border: 1px solid transparent;
  transition: background var(--t-fast), border-color var(--t-fast);
}

.purchase-item:hover:not(.disabled) {
  background: rgba(0, 242, 254, 0.05);
  border-color: rgba(0, 242, 254, 0.3);
}

.purchase-item.disabled {
  opacity: 0.5;
}

.purchase-item:focus-visible {
  outline: 2px solid var(--phase-primary);
  outline-offset: -2px;
}

.purchase-name {
  font-weight: 600;
  color: var(--c-lum-100);
}

.purchase-desc {
  flex: 1;
  font-size: 0.75rem;
  color: var(--c-lum-60);
  min-width: 100px;
}

.purchase-cost {
  font-size: 0.75rem;
  color: var(--c-aurora-gold);
  font-weight: 500;
}

.max-label {
  font-size: 0.6875rem;
  color: var(--c-lum-50);
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

/* ------------------------------------------------------------------------
   UPGRADES PANELS
   ------------------------------------------------------------------------ */
.upgrades-panel,
.doctrine-upgrades-panel,
.permanent-upgrades-panel {
  min-height: 150px;
}

.upgrade-list {
  display: flex;
  flex-direction: column;
  gap: var(--s-2);
}

.upgrade-item {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: var(--s-2);
  padding: var(--s-2);
  background: rgba(0, 0, 0, 0.2);
  border-radius: var(--r-sm);
  transition: background var(--t-fast);
}

.upgrade-item:hover:not(.disabled) {
  background: rgba(0, 242, 254, 0.05);
}

.upgrade-item.disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

.upgrade-item.owned {
  border-left: 3px solid var(--c-success);
}

.upgrade-item:focus-visible {
  outline: 2px solid var(--phase-primary);
  outline-offset: -2px;
}

.upgrade-name {
  font-weight: 600;
  color: var(--c-lum-100);
}

.upgrade-desc {
  flex: 1;
  font-size: 0.75rem;
  color: var(--c-lum-60);
}

.upgrade-cost {
  font-size: 0.75rem;
  color: var(--c-aurora-gold);
  font-weight: 500;
}

.upgrade-level {
  font-size: 0.6875rem;
  color: var(--c-aurora-cyan);
  font-weight: 500;
}

.requirement {
  font-size: 0.6875rem;
  color: var(--c-lum-50);
  font-style: italic;
}

.permanent-upgrades-panel .upgrade-cost {
  color: var(--c-aurora-magenta);
}

/* ------------------------------------------------------------------------
   DOCTRINE PANEL
   ------------------------------------------------------------------------ */
.doctrine-panel {
  min-height: 140px;
}

.doctrine-list {
  display: flex;
  flex-direction: column;
  gap: var(--s-2);
}

.doctrine-item {
  display: flex;
  flex-direction: column;
  gap: var(--s-1);
}

.doctrine-desc {
  font-size: 0.75rem;
  color: var(--c-lum-50);
  padding-left: var(--s-2);
}

.btn-doctrine {
  width: 100%;
  text-align: left;
  position: relative;
  overflow: hidden;
}

.btn-doctrine::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 2px;
  background: linear-gradient(90deg, transparent, var(--phase-primary), transparent);
  opacity: 0;
  transition: opacity var(--t-normal);
}

.btn-doctrine:hover:not(.disabled):not(.chosen)::before {
  opacity: 1;
}

.btn-doctrine.chosen {
  background: linear-gradient(135deg, rgba(0, 242, 254, 0.2), rgba(79, 0, 245, 0.2));
  border-color: var(--phase-primary);
  color: var(--c-lum-100);
  cursor: default;
}

.btn-doctrine.disabled {
  opacity: 0.4;
  cursor: not-allowed;
}

.no-doctrine {
  color: var(--c-lum-50);
  font-style: italic;
  text-align: center;
  padding: var(--s-4);
}

/* ------------------------------------------------------------------------
   RETUNE PANEL
   ------------------------------------------------------------------------ */
.retune-panel {
  background: linear-gradient(135deg, rgba(79, 0, 245, 0.15), rgba(255, 0, 230, 0.1));
  border-color: rgba(79, 0, 245, 0.3);
}

.retune-panel .panel-header {
  color: var(--c-aurora-purple);
}

.info-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: var(--s-1) 0;
}

.info-label {
  color: var(--c-lum-60);
  font-size: 0.75rem;
}

.info-value {
  color: var(--c-lum-100);
  font-weight: 600;
  font-size: 0.875rem;
}

#retuneBtn {
  width: 100%;
  margin-top: var(--s-2);
  padding: var(--s-3);
  font-size: 1rem;
  letter-spacing: 0.05em;
}

/* ------------------------------------------------------------------------
   SETTINGS PANEL
   ------------------------------------------------------------------------ */
.settings-panel {
  background: rgba(10, 10, 26, 0.7);
}

.setting-row {
  display: flex;
  align-items: center;
  gap: var(--s-2);
  padding: var(--s-1) 0;
}

.setting-label {
  flex: 1;
  color: var(--c-lum-60);
  font-size: 0.8125rem;
}

.setting-value {
  color: var(--c-lum-100);
  font-weight: 500;
  font-size: 0.875rem;
  min-width: 60px;
  text-align: right;
}

.hidden {
  display: none !important;
}

/* ------------------------------------------------------------------------
   BUTTONS - Shared Styles
   ------------------------------------------------------------------------ */
button,
.btn {
  font-family: var(--font-family);
  cursor: pointer;
  border: none;
  border-radius: var(--r-sm);
  padding: var(--s-2) var(--s-4);
  font-size: 0.875rem;
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  transition: all var(--t-fast);
  background: rgba(0, 242, 254, 0.1);
  color: var(--c-lum-100);
  border: 1px solid rgba(0, 242, 254, 0.3);
}

button:hover:not(.disabled),
.btn:hover:not(.disabled) {
  background: rgba(0, 242, 254, 0.2);
  border-color: rgba(0, 242, 254, 0.5);
  box-shadow: var(--shadow-glow-cyan);
}

button:active:not(.disabled),
.btn:active:not(.disabled) {
  background: rgba(0, 242, 254, 0.3);
  transform: scale(0.98);
}

button:focus-visible,
.btn:focus-visible {
  outline: 2px solid var(--phase-primary);
  outline-offset: 2px;
}

button.disabled,
.btn.disabled {
  opacity: 0.4;
  cursor: not-allowed;
  transform: none;
}

/* ------------------------------------------------------------------------
   RESPONSIVE BREAKPOINTS
   ------------------------------------------------------------------------ */

/* Tablet - adjust side columns */
@media (max-width: 1200px) {
  .main-panels {
    grid-template-columns: minmax(200px, 240px) 1fr minmax(200px, 240px);
  }
}

/* Mobile Landscape / Small Tablet */
@media (max-width: 900px) {
  .main-panels {
    grid-template-columns: minmax(180px, 200px) 1fr minmax(180px, 200px);
  }
}

/* Mobile Portrait */
@media (max-width: 768px) {
  #uiRoot {
    padding: var(--s-2);
    padding-bottom: calc(var(--s-2) + env(safe-area-inset-bottom, 0px));
  }

  .main-panels {
    display: flex;
    flex-direction: column;
    gap: var(--s-3);
  }

  .left-column,
  .right-column {
    grid-column: auto;
    width: 100%;
  }

  .panel-column {
    gap: var(--s-2);
  }

  .panel {
    max-height: 300px;
  }

  .purchase-panel,
  .upgrades-panel,
  .doctrine-upgrades-panel,
  .permanent-upgrades-panel,
  .retune-panel {
    min-height: auto;
  }

  /* Stack top bar and main panels with playfield band */
  .ui-container {
    gap: var(--s-2);
  }

  /* Ensure playfield visibility between controls */
  .main-panels::before {
    content: '';
    display: block;
    height: 120px;
    background: transparent;
    pointer-events: none;
  }
}

/* Narrow Mobile */
@media (max-width: 360px) {
  .stats-panel {
    flex-direction: column;
    align-items: stretch;
    gap: var(--s-2);
  }

  .stat-row {
    flex-direction: column;
    align-items: flex-start;
    gap: var(--s-1);
  }

  .main-panels::before {
    height: 80px;
  }

  .panel {
    max-height: 250px;
  }

  button,
  .btn {
    padding: var(--s-2);
    font-size: 0.8125rem;
  }
}

/* Reduced Motion */
@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }
}

/* Focus Visibility */
:focus:not(:focus-visible) {
  outline: none;
}

/* Safe area insets for notched devices */
@supports (padding-bottom: env(safe-area-inset-bottom)) {
  #uiRoot {
    padding-bottom: calc(var(--s-4) + env(safe-area-inset-bottom, 0px));
  }
}
ENDOFFILE
"}

