/* =============================================================================
   GLIMWEAVE - Sky Loom Instrument Styles
   Procedural aurora-workshop visual system. No external assets, no URLs.
   ============================================================================= */

/* ------------------------------------------------------------------------
   CSS Custom Properties & Foundation
   ------------------------------------------------------------------------ */
:root {
  /* Core Colors - Deep Space Aurora */
  --c-space-900: #0a0a1a;
  --c-space-800: #101424;
  --c-space-700: #1a1f3a;
  --c-space-600: #252b50;
  --c-space-500: #333a6b;

  /* Aurora Spectrum */
  --c-aurora-cyan: #00f2fe;
  --c-aurora-purple: #4f00f5;
  --c-aurora-green: #00ff85;
  --c-aurora-magenta: #ff00e6;
  --c-aurora-gold: #ffd700;
  --c-aurora-blue: #00a2ff;

  /* Luminance */
  --c-lum-0: #000000;
  --c-lum-10: #1a1a2e;
  --c-lum-20: #16213e;
  --c-lum-30: #0f3460;
  --c-lum-80: #a0a0c0;
  --c-lum-90: #d0d0f0;
  --c-lum-100: #ffffff;
  --c-lum-110: #00f2fe;

  /* Semantic */
  --c-success: #00ff85;
  --c-warning: #ffd700;
  --c-danger: #ff4757;
  --c-info: #00a2ff;

  /* Spacing - 4px base grid */
  --s-0: 0;
  --s-1: 0.25rem;
  --s-2: 0.5rem;
  --s-3: 0.75rem;
  --s-4: 1rem;
  --s-5: 1.25rem;
  --s-6: 1.5rem;
  --s-8: 2rem;
  --s-10: 2.5rem;
  --s-12: 3rem;
  --s-16: 4rem;

  /* Border Radius */
  --r-sm: 0.25rem;
  --r-md: 0.5rem;
  --r-lg: 0.75rem;
  --r-xl: 1.5rem;
  --r-full: 9999px;

  /* Shadows - Procedural Glow */
  --shadow-glow-cyan: 0 0 8px rgba(0, 242, 254, 0.3), 0 0 16px rgba(0, 242, 254, 0.15);
  --shadow-glow-purple: 0 0 8px rgba(79, 0, 245, 0.3), 0 0 16px rgba(79, 0, 245, 0.15);
  --shadow-glow-green: 0 0 8px rgba(0, 255, 133, 0.3), 0 0 16px rgba(0, 255, 133, 0.15);
  --shadow-glow-gold: 0 0 8px rgba(255, 215, 0, 0.3), 0 0 16px rgba(255, 215, 0, 0.15);
  --shadow-glow-white: 0 0 12px rgba(255, 255, 255, 0.4), 0 0 24px rgba(255, 255, 255, 0.2);
  --shadow-inset: inset 0 1px 0 rgba(255, 255, 255, 0.05), inset 0 -1px 0 rgba(0, 0, 0, 0.3);

  /* Transitions */
  --t-fast: 100ms ease;
  --t-normal: 200ms ease;
  --t-slow: 400ms ease;

  /* Font */
  --font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Oxygen, Ubuntu, Cantarell, sans-serif;
  --font-mono: "SF Mono", "Monaco", "Inconsolata", "Fira Code", monospace;

  /* Touch Targets */
  --touch-min: 44px;
}

/* ------------------------------------------------------------------------
   BASE RESET & HTML SHELL
   ------------------------------------------------------------------------ */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  font-size: 16px;
  scroll-behavior: smooth;
  -webkit-text-size-adjust: 100%;
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

body {
  min-height: 100vh;
  min-height: 100dvh;
  margin: 0;
  padding: 0;
  background: var(--c-space-900);
  color: var(--c-lum-90);
  font-family: var(--font-family);
  line-height: 1.5;
